import { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@500;700&family=DM+Sans:wght@300;400;500&display=swap');

  :root {
    --bg: #f5f0e8;
    --surface: #faf7f2;
    --border: #e2d9cc;
    --ink: #1a1612;
    --ink-muted: #7a6f63;
    --accent: #c8441a;
  }

  .page-root {
    min-height: 100vh;
    background: var(--bg);
    font-family: 'DM Sans', sans-serif;
    color: var(--ink);
    padding: 80px 24px 80px;
  }

  .page-inner {
    max-width: 680px;
    margin: 0 auto;
  }

  .page-header {
    display: flex;
    align-items: baseline;
    gap: 12px;
    margin-bottom: 24px;
    padding-bottom: 20px;
    border-bottom: 1.5px solid var(--border);
  }

  .page-header h2 {
    font-family: 'Playfair Display', serif;
    font-size: 2.2rem;
    font-weight: 700;
    letter-spacing: -0.02em;
    line-height: 1;
    color: var(--ink);
  }

  .page-header .dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: var(--accent);
    flex-shrink: 0;
    margin-bottom: 4px;
  }

  .project-card {
    background: var(--surface);
    border: 1.5px solid var(--border);
    border-radius: 10px;
    padding: 20px 24px;
    margin-bottom: 16px;
    transition: transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease;
  }

  .project-card:hover {
    border-color: #c8b9a8;
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(26,22,18,0.05);
  }

  .project-title {
    font-size: 1.1rem;
    font-weight: 600;
    color: var(--ink);
    margin-bottom: 6px;
    display: flex;
    align-items: center;
    gap: 8px;
  }

  .project-desc {
    font-size: 0.9rem;
    color: var(--ink-muted);
    margin-bottom: 12px;
    line-height: 1.5;
  }

  .project-owner {
    font-size: 0.8rem;
    color: var(--ink-muted);
    margin-bottom: 16px;
  }

  .btn-follow {
    background: transparent;
    border: 1.5px solid var(--accent);
    color: var(--accent);
    padding: 6px 14px;
    border-radius: 6px;
    font-size: 0.85rem;
    font-weight: 500;
    cursor: pointer;
    transition: all 200ms ease;
  }

  .btn-follow:hover {
    background: var(--accent);
    color: #fff;
  }

  .btn-follow.active {
    background: var(--accent);
    color: #fff;
  }

  .empty-msg {
    color: var(--ink-muted);
    font-size: 0.9rem;
    font-style: italic;
  }
`;

export default function ProjectHub() {
  const [projects, setProjects] = useState([]);
  const [user, setUser] = useState(null); // ✅ moved inside component

  useEffect(() => {
    init();
  }, []);

  const init = async () => {
    const { data } = await supabase.auth.getUser();
    setUser(data.user);
    fetchProjects(data.user);
  };

  // ✅ SINGLE fetchProjects (removed duplicate)
  const fetchProjects = async (currentUser) => {
    const { data: projectsData } = await supabase
      .from("projects")
      .select(`
        *,
        profiles(name)
      `)
      .order("created_at", { ascending: false });

    const { data: follows } = await supabase
      .from("project_followers")
      .select("project_id")
      .eq("user_id", currentUser.id);

    const followedIds = follows?.map((f) => f.project_id) || [];

    const merged = projectsData.map((proj) => ({
      ...proj,
      isFollowing: followedIds.includes(proj.id),
    }));

    setProjects(merged);
  };

  // ✅ FOLLOW FUNCTION (you forgot this)
  const followProject = async (projectId) => {
    if (!user) return;

    const already = projects.find(
      (p) => p.id === projectId && p.isFollowing
    );

    if (already) return;

    const { error } = await supabase.from("project_followers").insert([
      {
        user_id: user.id,
        project_id: projectId,
      },
    ]);

    if (!error) {
      fetchProjects(user);
    }
  };

  return (
    <>
      <style>{styles}</style>
      <div className="page-root">
        <div className="page-inner">
          <div className="page-header">
            <h2>Project Hub</h2>
            <div className="dot" />
          </div>

          {projects.length === 0 ? (
            <p className="empty-msg">No projects yet</p>
          ) : (
            projects.map((proj) => (
              <div key={proj.id} className="project-card">
                <div className="project-title">
                  🚀 {proj.title}
                </div>
                
                <p className="project-desc">{proj.description}</p>

                <p className="project-owner">
                  👤 {proj.profiles?.name || "User"}
                </p>

                <button
                  className={`btn-follow ${proj.isFollowing ? "active" : ""}`}
                  onClick={() => followProject(proj.id)}
                >
                  {proj.isFollowing ? "Following" : "Follow Project"}
                </button>
              </div>
            ))
          )}
        </div>
      </div>
    </>
  );
}
